from flask import Flask, request, redirect, url_for
from flask_oidc import OpenIDConnect

app = Flask(__name__)
app.config["OIDC_CLIENT_SECRETS"] = "client_secrets.json"
app.config["OIDC_REDIRECT_URI"] = url_for("authorized", _external=True)
oidc = OpenIDConnect(app)

@app.route("/")
def index():
    return redirect(url_for("authorize"))

@app.route("/authorize")
def authorize():
    return oidc.authorize(client_id="YOUR_CLIENT_ID", redirect_uri=url_for("callback", _external=True), scope="openid", response_type="id_token")

@app.route("/callback")
def callback():
    id_token = request.args.get("id_token")
    if not id_token:
        return "Error: no ID token in callback"
    userinfo = oidc.userinfo(id_token)
    # Use the userinfo to authenticate the user and grant access to the admin dashboard
    return redirect(url_for("admin"))

@app.route("/admin")
def admin():
    return "Admin Dashboard"